2105 /// Given operands for an And, see if we can fold the result.
2106 /// If not, this returns null.
2107 static Value *simplifyAndInst(Value *Op0, Value *Op1, const SimplifyQuery &Q,
2108                               unsigned MaxRecurse) {
2109   if (Constant *C = foldOrCommuteConstant(Instruction::And, Op0, Op1, Q))
2110     return C;
2111 
2112   // X & poison -> poison
2113   if (isa<PoisonValue>(Op1))
2114     return Op1;
2115 
2116   // X & undef -> 0
2117   if (Q.isUndefValue(Op1))
2118     return Constant::getNullValue(Op0->getType());
2119 
2120   // X & X = X
2121   if (Op0 == Op1)
2122     return Op0;
2123 
2124   // X & 0 = 0
2125   if (match(Op1, m_Zero()))
2126     return Constant::getNullValue(Op0->getType());
2127 
2128   // X & -1 = X
2129   if (match(Op1, m_AllOnes()))
2130     return Op0;
2131 
2132   // A & ~A  =  ~A & A  =  0
2133   if (match(Op0, m_Not(m_Specific(Op1))) || match(Op1, m_Not(m_Specific(Op0))))
2134     return Constant::getNullValue(Op0->getType());
2135 
2136   // (A | ?) & A = A
2137   if (match(Op0, m_c_Or(m_Specific(Op1), m_Value())))
2138     return Op1;
2139 
2140   // A & (A | ?) = A
2141   if (match(Op1, m_c_Or(m_Specific(Op0), m_Value())))
2142     return Op0;
2143 
2144   // (X | Y) & (X | ~Y) --> X (commuted 8 ways)
2145   Value *X, *Y;
2146   if (match(Op0, m_c_Or(m_Value(X), m_Not(m_Value(Y)))) &&
2147       match(Op1, m_c_Or(m_Deferred(X), m_Deferred(Y))))
2148     return X;
2149   if (match(Op1, m_c_Or(m_Value(X), m_Not(m_Value(Y)))) &&
2150       match(Op0, m_c_Or(m_Deferred(X), m_Deferred(Y))))
2151     return X;
2152 
2153   if (Value *V = simplifyLogicOfAddSub(Op0, Op1, Instruction::And))
2154     return V;
