2186   // If we have a multiplication overflow check that is being 'and'ed with a
2187   // check that one of the multipliers is not zero, we can omit the 'and', and
2188   // only keep the overflow check.
2189   if (isCheckForZeroAndMulWithOverflow(Op0, Op1, true))
